// 'myForm'というidを持つ要素に対する'submit'イベントの設定
let myForm = document.getElementById('myForm');
myForm.addEventListener('submit', function(event) {
  console.log('Form submitted!');
  // ここでフォームの送信をキャンセルします
  event.preventDefault();
});
// これを実行すると、'myForm'が送信されたとき、
// コンソールに'Form submitted!'が表示され、ページ遷移は発生しません。

// キーボードの'a'キーの押下イベントの取得
window.addEventListener('keydown', function(event) {
  if (event.key === 'a') {
    console.log('Key a was pressed!');
  }
});
// これを実行すると、'a'キーが押されたとき、
// コンソールに'Key a was pressed!'と表示されます。

// 'myButton'というidを持つ要素に対する2つのクリックイベントリスナーの設定
let myButton = document.getElementById('myButton');
myButton.addEventListener('click', function() {
  console.log('First listener!');
});
myButton.addEventListener('click', function() {
  console.log('Second listener!');
});
// これを実行すると、'myButton'がクリックされたとき、
// コンソールには'First listener!'と'Second listener!'が順番に表示されます。

// 'myButton'というidを持つ要素に対するクリックイベントリスナーの設定と削除
let myButton = document.getElementById('myButton');
// 関数を別途定義します
let myListener = function() {
  console.log('Button was clicked!');
};
// イベントリスナーを設定
myButton.addEventListener('click', myListener);
// イベントリスナーを削除
myButton.removeEventListener('click', myListener);
// これを実行すると、'myButton'がクリックされたとき、何も表示されません。
// (イベントリスナーはすでに削除されているためです)

// 'myElement'というidを持つ要素に対するマウスオーバーイベントの設定
let myElement = document.getElementById('myElement');
myElement.addEventListener('mouseover', function() {
  console.log("You're hovering over me!");
});
// これを実行すると、マウスが'myElement'の上に乗ったとき、
// コンソールに'You're hovering over me!'と表示されます。
